import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { dashboardApi, authApi, auth } from '../services/api';

const S = {
  page: { background: 'var(--color-bg)', minHeight: 'calc(100vh - 64px)' },
  header: {
    background: 'var(--color-dark)', padding: '40px 32px 36px',
    borderBottom: '1px solid var(--color-dark-border)',
  },
  headerInner: { maxWidth: 1100, margin: '0 auto' },
  welcome: { fontSize: 'clamp(1.5rem,3vw,2rem)', fontWeight: 'var(--weight-bold)', color: '#fff', marginBottom: 6 },
  memberSince: { fontSize: 'var(--text-sm)', color: 'var(--color-dark-muted)' },
  body: { maxWidth: 1100, margin: '0 auto', padding: '40px 32px 80px' },
  statsGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(180px,1fr))', gap: 16, marginBottom: 48 },
  statCard: {
    background: '#fff', border: '1px solid var(--color-stone)',
    borderRadius: 'var(--radius-xl)', padding: '20px 24px',
    display: 'flex', flexDirection: 'column', gap: 8,
  },
  statLabel: { fontSize: 'var(--text-xs)', fontWeight: 'var(--weight-semibold)', letterSpacing: 'var(--tracking-wider)', textTransform: 'uppercase', color: 'var(--color-text-muted)' },
  statVal: { fontSize: 'var(--text-3xl)', fontWeight: 'var(--weight-bold)', color: 'var(--color-text-primary)' },
  section: { marginBottom: 48 },
  sectionTitle: { fontSize: 'var(--text-xl)', fontWeight: 'var(--weight-semibold)', color: 'var(--color-text-primary)', marginBottom: 16, paddingBottom: 12, borderBottom: '1px solid var(--color-stone)' },
  keyCard: {
    background: '#fff', border: '1px solid var(--color-stone)', borderRadius: 'var(--radius-xl)',
    padding: '16px 20px', display: 'flex', alignItems: 'center',
    justifyContent: 'space-between', gap: 12, marginBottom: 10,
  },
  keyName: { fontWeight: 'var(--weight-semibold)', color: 'var(--color-text-primary)', fontSize: 'var(--text-sm)' },
  keyPrefix: { fontFamily: 'var(--font-mono)', fontSize: 'var(--text-xs)', color: 'var(--color-gold)', background: 'var(--color-gold-light)', padding: '2px 8px', borderRadius: 4 },
  keyMeta: { fontSize: 'var(--text-xs)', color: 'var(--color-text-muted)' },
  savedGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(240px,1fr))', gap: 14 },
  savedCard: { background: '#fff', border: '1px solid var(--color-stone)', borderRadius: 'var(--radius-xl)', padding: '16px', display: 'flex', flexDirection: 'column', gap: 8 },
  savedName: { fontWeight: 'var(--weight-semibold)', fontSize: 'var(--text-sm)', color: 'var(--color-text-primary)' },
  savedDomain: { fontSize: 'var(--text-xs)', color: 'var(--color-text-muted)' },
  searchItem: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 0', borderBottom: '1px solid var(--color-stone)' },
  searchQuery: { fontSize: 'var(--text-sm)', color: 'var(--color-text-primary)', fontStyle: 'italic' },
  searchMeta: { fontSize: 'var(--text-xs)', color: 'var(--color-text-muted)' },
  modal: {
    position: 'fixed', inset: 0, background: 'rgba(26,25,23,0.6)',
    display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 400, padding: 20,
  },
  modalBox: {
    background: '#fff', borderRadius: 'var(--radius-2xl)', padding: '36px',
    maxWidth: 420, width: '100%', boxShadow: 'var(--shadow-2xl)',
  },
  newKeyBox: {
    padding: '16px', background: 'var(--color-gold-light)', border: '1px solid var(--color-gold)',
    borderRadius: 'var(--radius-lg)', fontFamily: 'var(--font-mono)', fontSize: 'var(--text-sm)',
    wordBreak: 'break-all', marginBottom: 12, color: 'var(--color-gold-dark)',
  },
  quickActions: { display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 12 },
  qaCard: {
    padding: '20px 16px', background: '#fff', border: '1px solid var(--color-stone)',
    borderRadius: 'var(--radius-xl)', textAlign: 'center', textDecoration: 'none',
    transition: 'all 200ms',
  },
};

function StatCard({ label, value, loading }) {
  return (
    <div style={S.statCard}>
      <div style={S.statLabel}>{label}</div>
      <div style={S.statVal}>{loading ? '—' : (value ?? 0).toLocaleString()}</div>
    </div>
  );
}

export default function Dashboard() {
  const navigate = useNavigate();
  const [dashboard, setDashboard] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [newKeyName, setNewKeyName] = useState('');
  const [newKey, setNewKey] = useState('');
  const [genLoading, setGenLoading] = useState(false);
  const [revokeConfirm, setRevokeConfirm] = useState(null);
  const [keyCopied, setKeyCopied] = useState(false);

  useEffect(() => {
    if (!auth.isLoggedIn()) { navigate('/login'); return; }
    dashboardApi.get()
      .then(r => setDashboard(r.data))
      .catch(() => navigate('/login'))
      .finally(() => setLoading(false));
  }, [navigate]);

  const generateKey = async () => {
    if (!newKeyName.trim()) return;
    setGenLoading(true);
    try {
      const res = await authApi.createApiKey(newKeyName.trim());
      setNewKey(res.data.raw_key || res.data.api_key || 'Key generated — check response');
      setNewKeyName('');
    } catch (e) {
      alert(e.message);
    } finally {
      setGenLoading(false);
    }
  };

  const revokeKey = async (keyId) => {
    try {
      await authApi.revokeApiKey(keyId);
      setDashboard(prev => ({
        ...prev,
        api_keys: prev.api_keys.filter(k => k.id !== keyId),
      }));
      setRevokeConfirm(null);
    } catch (e) {
      alert(e.message);
    }
  };

  const copyKey = () => { navigator.clipboard.writeText(newKey); setKeyCopied(true); setTimeout(() => setKeyCopied(false), 1800); };

  if (loading) return (
    <div style={{ ...S.page, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <span className="spinner spinner-lg" />
    </div>
  );

  const { user, stats, api_keys = [], saved_datasets = [], recent_searches = [] } = dashboard || {};

  return (
    <div style={S.page} className="page-enter">
      {/* Header */}
      <div style={S.header}>
        <div style={S.headerInner}>
          <h1 style={S.welcome}>Welcome back, {user?.username} 👋</h1>
          <p style={S.memberSince}>Member since {new Date(user?.member_since).toLocaleDateString()}</p>
        </div>
      </div>

      <div style={S.body}>
        {/* Stats */}
        <div style={S.statsGrid}>
          <StatCard label="Total API Calls" value={stats?.total_api_calls} />
          <StatCard label="Active API Keys" value={stats?.active_api_keys} />
          <StatCard label="Saved Datasets" value={stats?.saved_datasets} />
          <StatCard label="Datasets Available" value={stats?.total_available_datasets} />
        </div>

        {/* Quick Actions */}
        <div style={S.section}>
          <div style={S.sectionTitle}>Quick Actions</div>
          <div style={S.quickActions}>
            {[
              { to: '/buildpilot', icon: '🧠', label: 'Launch BuildPilot' },
              { to: '/explore', icon: '🗄️', label: 'Explore Datasets' },
              { to: '/console', icon: '⚙️', label: 'Open API Console' },
            ].map(a => (
              <Link key={a.to} to={a.to} style={S.qaCard}
                onMouseEnter={e => { e.currentTarget.style.borderColor = 'var(--color-gold)'; e.currentTarget.style.boxShadow = 'var(--shadow-md)'; e.currentTarget.style.transform = 'translateY(-2px)'; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = 'var(--color-stone)'; e.currentTarget.style.boxShadow = 'none'; e.currentTarget.style.transform = 'none'; }}>
                <div style={{ fontSize: '1.75rem', marginBottom: 10 }}>{a.icon}</div>
                <div style={{ fontWeight: 'var(--weight-semibold)', fontSize: 'var(--text-sm)', color: 'var(--color-text-primary)' }}>{a.label}</div>
              </Link>
            ))}
          </div>
        </div>

        {/* API Keys */}
        <div style={S.section}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16, borderBottom: '1px solid var(--color-stone)', paddingBottom: 12 }}>
            <div style={{ ...S.sectionTitle, marginBottom: 0, paddingBottom: 0, border: 'none' }}>API Keys</div>
            <button className="btn btn-gold btn-sm" onClick={() => setShowModal(true)}>+ Generate New Key</button>
          </div>
          {api_keys.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '32px', color: 'var(--color-text-muted)', background: 'var(--color-surface)', borderRadius: 'var(--radius-xl)', border: '1px solid var(--color-stone)' }}>
              No API keys yet. Generate your first key to start using OmniCore.
            </div>
          ) : (
            api_keys.map(k => (
              <div key={k.id} style={S.keyCard}>
                <div style={{ flex: 1 }}>
                  <div style={{ display: 'flex', gap: 10, alignItems: 'center', marginBottom: 4 }}>
                    <span style={S.keyName}>{k.name}</span>
                    <span style={S.keyPrefix}>{k.key_prefix}...</span>
                  </div>
                  <div style={S.keyMeta}>
                    {k.usage_count} calls · Last used: {k.last_used ? new Date(k.last_used).toLocaleDateString() : 'Never'} · Created {new Date(k.created_at).toLocaleDateString()}
                  </div>
                </div>
                {revokeConfirm === k.id ? (
                  <div style={{ display: 'flex', gap: 6 }}>
                    <button className="btn btn-sm" style={{ background: 'var(--color-error)', color: '#fff', border: 'none' }} onClick={() => revokeKey(k.id)}>Confirm Revoke</button>
                    <button className="btn btn-outline btn-sm" onClick={() => setRevokeConfirm(null)}>Cancel</button>
                  </div>
                ) : (
                  <button className="btn btn-ghost btn-sm" style={{ color: 'var(--color-error)' }} onClick={() => setRevokeConfirm(k.id)}>Revoke</button>
                )}
              </div>
            ))
          )}
        </div>

        {/* Saved Datasets */}
        <div style={S.section}>
          <div style={S.sectionTitle}>Saved Datasets</div>
          {saved_datasets.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '32px', color: 'var(--color-text-muted)', background: 'var(--color-surface)', borderRadius: 'var(--radius-xl)', border: '1px solid var(--color-stone)' }}>
              No saved datasets yet. <Link to="/explore" style={{ color: 'var(--color-gold-dark)' }}>Explore the Data Explorer</Link> to save datasets.
            </div>
          ) : (
            <div style={S.savedGrid}>
              {saved_datasets.map((s, i) => (
                <div key={i} style={S.savedCard}>
                  <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <span style={S.savedName}>{s.dataset?.name || s.dataset_id}</span>
                    <span className="badge badge-gold" style={{ fontSize: 9 }}>{s.dataset?.domain?.split(' ')[0]}</span>
                  </div>
                  <div style={S.savedDomain}>{s.dataset?.category}</div>
                  <div style={S.keyMeta}>Saved {new Date(s.saved_at).toLocaleDateString()}</div>
                  <Link to={`/datasets/${s.dataset?.slug || s.dataset_id}`} className="btn btn-outline btn-sm" style={{ marginTop: 4 }}>View →</Link>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Recent Searches */}
        {recent_searches.length > 0 && (
          <div style={S.section}>
            <div style={S.sectionTitle}>Recent Searches</div>
            {recent_searches.slice(0, 8).map((s, i) => (
              <div key={i} style={S.searchItem}>
                <Link to={`/explore?q=${encodeURIComponent(s.query)}`} style={{ ...S.searchQuery, textDecoration: 'none', color: 'var(--color-text-primary)' }}>
                  "{s.query}"
                </Link>
                <span style={S.searchMeta}>{s.results_count} results · {new Date(s.searched_at).toLocaleDateString()}</span>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Generate Key Modal */}
      {showModal && (
        <div style={S.modal} onClick={e => e.target === e.currentTarget && !newKey && setShowModal(false)}>
          <div style={S.modalBox} className="animate-scale-in">
            <h2 style={{ marginBottom: 20 }}>{newKey ? 'Your New API Key' : 'Generate API Key'}</h2>
            {newKey ? (
              <>
                <div style={{ padding: '12px', background: 'var(--color-warning-light)', border: '1px solid var(--color-warning)', borderRadius: 8, fontSize: 'var(--text-sm)', color: 'var(--color-warning)', marginBottom: 16 }}>
                  ⚠️ Save this key now — it will not be shown again.
                </div>
                <div style={S.newKeyBox}>{newKey}</div>
                <div style={{ display: 'flex', gap: 8 }}>
                  <button className="btn btn-gold" style={{ flex: 1 }} onClick={copyKey}>{keyCopied ? '✓ Copied!' : 'Copy Key'}</button>
                  <button className="btn btn-outline" onClick={() => { setNewKey(''); setShowModal(false); window.location.reload(); }}>Done</button>
                </div>
              </>
            ) : (
              <>
                <div className="form-group">
                  <label className="label">Key Name</label>
                  <input className="input" placeholder="e.g. Production Key" value={newKeyName} onChange={e => setNewKeyName(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && generateKey()} autoFocus />
                </div>
                <div style={{ display: 'flex', gap: 8 }}>
                  <button className="btn btn-gold" style={{ flex: 1 }} onClick={generateKey} disabled={genLoading || !newKeyName.trim()}>
                    {genLoading ? 'Generating…' : 'Generate Key'}
                  </button>
                  <button className="btn btn-outline" onClick={() => setShowModal(false)}>Cancel</button>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
